Опана! Извините за путаницу. Вместо navigateToURL вы можете использовать функцию navigateToURL из пакета flash.net.URLRequest:

public function openURL(event:MouseEvent):void {
    var button:MovieClip = event.target as MovieClip;
    var url:String = "";

    switch(button) {
        case discord:
            url = discordURL;
            break;
        case facebook:
            url = facebookURL;
            break;
        case telegram:
            url = telegramURL;
            break;
        case vk:
            url = vkURL;
            break;
        case youtube:
            url = youtubeURL;
            break;
    }

    var request:URLRequest = new URLRequest(url);
    navigateToURL(request, "_blank");
}

Очень извиняюсь за неудобства. В Flex SDK 4.6 метод navigateToURL доступен только для приложений AIR. Если вы разрабатываете веб-приложение, вам нужно использовать JavaScript для открытия ссылки в новом окне браузера. Вот код, который откроет ссылку в новой вкладке:

public function openURL(event:MouseEvent):void {
    var button:MovieClip = event.target as MovieClip;
    var url:String = "";

    switch(button) {
        case discord:
            url = discordURL;
            break;
        case facebook:
            url = facebookURL;
            break;
        case telegram:
            url = telegramURL;
            break;
        case vk:
            url = vkURL;
            break;
        case youtube:
            url = youtubeURL;
            break;
    }

    var script:String = "window.open('" + url + "', '_blank');";
    ExternalInterface.call("eval", script);
}

Также не забудьте добавить импорт для ExternalInterface:

import flash.external.ExternalInterface;

